import{_ as e,o as a,c as s,a2 as i}from"./chunks/framework.B08aFN1B.js";const k=JSON.parse('{"title":"Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"configuration.md","filePath":"configuration.md","lastUpdated":null}'),n={name:"configuration.md"};function l(o,t,r,h,d,g){return a(),s("div",null,[...t[0]||(t[0]=[i(`<h1 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h1><h2 id="Settings-" tabindex="-1">Settings (⚙) <a class="header-anchor" href="#Settings-" aria-label="Permalink to &quot;Settings (⚙) {#Settings-}&quot;">​</a></h2><p>Open the gear in the top bar (or ⌘K → Settings). Settings persist per-browser in localStorage.</p><table tabindex="0"><thead><tr><th style="text-align:right;">Setting</th><th style="text-align:right;">Effect</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>Live-update debounce</strong></td><td style="text-align:right;">Minimum delay (ms) between live recomputes while dragging a control. Higher = fewer recomputes on a slow kernel.</td></tr><tr><td style="text-align:right;"><strong>Full page width</strong></td><td style="text-align:right;">Use the full window width instead of the centered column.</td></tr><tr><td style="text-align:right;"><strong>Theme</strong></td><td style="text-align:right;">Dark (default).</td></tr><tr><td style="text-align:right;"><strong>Editor syntax</strong></td><td style="text-align:right;">Syntax-highlighting palette for the editor — Dark+, Monokai, Dracula, or Nord.</td></tr><tr><td style="text-align:right;"><strong>Agent model</strong></td><td style="text-align:right;">Sonnet / Opus / Haiku, plus any locally-installed Ollama model.</td></tr><tr><td style="text-align:right;"><strong>Agent permissions</strong></td><td style="text-align:right;"><code>lab</code> / <code>auto</code> / <code>default</code> / <code>bypass</code> preset for the agent.</td></tr></tbody></table><p>Model and permission changes <a href="./agent">reap the agent</a> so the next message respawns on the new setting (the transcript is kept).</p><p><img class="slate-shot" src="https://github.com/kahliburke/KaimonSlate.jl/releases/download/docs-assets/settings.png" alt=""></p><h2 id="serving" tabindex="-1">Serving <a class="header-anchor" href="#serving" aria-label="Permalink to &quot;Serving&quot;">​</a></h2><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KaimonSlate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">serve_notebook</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(path; host </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;127.0.0.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, port </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8765</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># blocking</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">h </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> KaimonSlate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">start_server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(path; host </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;127.0.0.1&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, port </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 8765</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># non-blocking → Hub</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">KaimonSlate</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stop_server</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(h)</span></span></code></pre></div><p><code>start_hub</code> / <code>open_notebook!</code> / <code>close_notebook!</code> / <code>stop_hub</code> give finer control over a multi-notebook hub. See the <a href="./api">API Reference</a>.</p><h2 id="Kernel-selection" tabindex="-1">Kernel selection <a class="header-anchor" href="#Kernel-selection" aria-label="Permalink to &quot;Kernel selection {#Kernel-selection}&quot;">​</a></h2><p>A notebook uses a <strong>gate worker</strong> when it sits inside a Julia project and Kaimon&#39;s gate is available; otherwise it runs <strong>in-process</strong>. The gate worker gives you a clean namespace, a tailable log (🪵), <a href="./packages">package management</a>, and isolation. There&#39;s no setting for this — it&#39;s chosen from the notebook&#39;s location. Restart a worker any time with <strong>⟲ Restart worker</strong> (top bar), or rebuild the namespace with <strong>↻ Rebuild</strong>.</p><h2 id="Ollama-local-models" tabindex="-1">Ollama (local models) <a class="header-anchor" href="#Ollama-local-models" aria-label="Permalink to &quot;Ollama (local models) {#Ollama-local-models}&quot;">​</a></h2><p>The agent model dropdown lists models from your local Ollama install, queried from its HTTP API (embedding-only models are filtered out). Point at a non-default host with the standard environment variable:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> OLLAMA_HOST</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">http://127.0.0.1:11434</span></span></code></pre></div><p>Driving a local model requires Kaimon&#39;s Ollama agent backend. Selecting a model stores it as <code>ollama:&lt;name&gt;</code>, which rides each chat turn.</p><h2 id="Environment-variables" tabindex="-1">Environment variables <a class="header-anchor" href="#Environment-variables" aria-label="Permalink to &quot;Environment variables {#Environment-variables}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Variable</th><th style="text-align:right;">Used for</th></tr></thead><tbody><tr><td style="text-align:right;"><code>OLLAMA_HOST</code></td><td style="text-align:right;">Ollama API endpoint for the model list (default <code>http://127.0.0.1:11434</code>).</td></tr><tr><td style="text-align:right;"><code>KAIMONSLATE_ASSET_BASE</code></td><td style="text-align:right;"><strong>Docs build only</strong> — points the site at the docs-assets GitHub Release for generated demo media. Unset locally → served from <code>public/assets/</code>.</td></tr></tbody></table>`,17)])])}const c=e(n,[["render",l]]);export{k as __pageData,c as default};
